class Solution {
public:
    int maximizeXor(vector<int>& a, int x) {
        int n = a.size();
        int ans = 0;

        for (int b = 0; b < 30; ++b) {
            int ct = 0;

            for (int y : a) {
                if ((y >> b) & 1) ct++;
            }

            if (ct == 0 || ct == n) continue;

            int cur = 0;
            for (int bit = 29; bit >= 0; --bit) {
                if (bit == b) continue;           
                if (cur + (1 << bit) > x) continue; 
                cur += (1 << bit);
            }

            ans = max(ans, cur);
        }

        return ans;
    }
};

